 import sailpoint.api.*;
 import sailpoint.object.*;
 import sailpoint.object.EmailTemplate;
 import sailpoint.object.EmailOptions;


 log.error("--workflow is triggered for sending an email--");
 EmailTemplate template=context.getObjectByName(EmailTemplate.class,emailTemplateName);
 if(template!=null){

 log.error("----identityName----"+identityName);
 log.error("----emailTemplateName----"+emailTemplateName);

 // EmailTemplate template=new EmailTemplate();
